<!-- 功能说明
管理端公告管理核心页面，支持公告的新增、编辑、删除、预览，
使用富文本编辑器编辑公告内容，核心对接公告管理相关接口，完善内容运营能力�� -->�


<template>
  <view class="notice-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">公告管理</text>
      <button class="add-btn" @click="showAddModal">+ 新增公告</button>
    </view>

    <!-- 公告列表 -->
    <view class="notice-list" v-if="noticeList.length > 0">
      <view class="notice-item" v-for="(item, index) in noticeList" :key="item.id">
        <view class="notice-header">
          <text class="notice-title">{{item.title}}</text>
          <text class="notice-time">{{formatTime(item.createTime)}}</text>
        </view>
        <text class="notice-content">{{item.content.slice(0, 50)}}{{item.content.length > 50 ? '...' : ''}}</text>
        <view class="operation-group">
          <button class="oper-btn preview-btn" @click="previewNotice(item)">预览</button>
          <button class="oper-btn edit-btn" @click="showEditModal(item, index)">编辑</button>
          <button class="oper-btn delete-btn" @click="deleteNotice(item.id, index)">删除</button>
        </view>
      </view>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty-notice.png" class="empty-img"></image>
      <text class="empty-text">暂无公告数据，点击右上角新增</text>
    </view>

    <!-- 新增/编辑公告弹窗 -->
    <uni-modal 
      :title="isEditMode ? '编辑公告' : '新增公告'" 
      :visible="modalVisible" 
      width="95%"
      @confirm="confirmSubmit"
      @cancel="hideModal"
    >
      <view class="notice-form">
        <!-- 公告标题 -->
        <view class="form-item">
          <text class="form-label required">公告标题：</text>
          <input 
            class="form-input" 
            v-model="formData.title" 
            placeholder="请输入公告标题"
            maxlength="50"
          ></input>
        </view>

        <!-- 公告内容（富文本编辑器） -->
        <view class="form-item">
          <text class="form-label required">公告内容：</text>
          <editor 
            class="editor"
            :value="formData.content"
            :placeholder="isEditMode ? '编辑公告内容' : '请输入公告内容'"
            @input="handleEditorInput"
          ></editor>
        </view>
      </view>
    </uni-modal>

    <!-- 公告预览弹窗 -->
    <uni-modal 
      title="公告预览" 
      :visible="previewVisible" 
      width="95%"
      @cancel="hidePreviewModal"
    >
      <view class="preview-container">
        <text class="preview-title">{{previewNoticeInfo.title || ''}}</text>
        <text class="preview-time">{{formatTime(previewNoticeInfo.createTime) || ''}}</text>
        <rich-text :nodes="previewNoticeInfo.content || ''" class="preview-content"></rich-text>
      </view>
    </uni-modal>
  </view>
</template>
<script setup>
import { ref } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';

import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const noticeList = ref([]); // 公告列表
const modalVisible = ref(false); // 新增/编辑弹窗
const previewVisible = ref(false); // 预览弹窗
const isEditMode = ref(false); // 是否编辑模式
const currentIndex = ref(-1); // 当前编辑索引
const formData = ref({
  id: '', // 公告ID（编辑模式）
  title: '', // 公告标题
  content: '' // 公告内容
});
const previewNoticeInfo = ref({}); // 预览公告信息
const isSubmitting = ref(false); // 提交状态

// 页面加载时获取公告列表
onLoad(() => {
  if (!userStore.token || userStore.userInfo.role !== 'ADMIN') {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getNoticeList();
});

onShow(() => {
  getNoticeList();
});

// 接口请求：获取公告列表
const getNoticeList = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/admin/notice/list',
      method: 'GET'
    });
    if (res.success) {
      // 按创建时间倒序排序
      noticeList.value = res.data.sort((a, b) => new Date(b.createTime) - new Date(a.createTime));
    }
  } catch (error) {
    uni.showToast({ title: '公告列表加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 显示新增弹窗
const showAddModal = () => {
  isEditMode.value = false;
  formData.value = { id: '', title: '', content: '' };
  modalVisible.value = true;
};

// 显示编辑弹窗
const showEditModal = (item, index) => {
  isEditMode.value = true;
  currentIndex.value = index;
  formData.value = { ...item };
  modalVisible.value = true;
};

// 隐藏弹窗
const hideModal = () => {
  modalVisible.value = false;
};

// 富文本编辑器输入处理
const handleEditorInput = (e) => {
  formData.value.content = e.detail.html;
};

// 提交新增/编辑
const confirmSubmit = async () => {
  // 表单校验
  if (!formData.value.title.trim()) {
    uni.showToast({ title: '请输入公告标题', icon: 'none' });
    return;
  }
  if (!formData.value.content.trim()) {
    uni.showToast({ title: '请输入公告内容', icon: 'none' });
    return;
  }

  isSubmitting.value = true;
  try {
    let res;
    if (isEditMode.value) {
      // 编辑公告
      res = await request({
        url: '/api/admin/notice/update',
        method: 'PUT',
        data: formData.value
      });
    } else {
      // 新增公告
      res = await request({
        url: '/api/admin/notice/add',
        method: 'POST',
        data: {
          title: formData.value.title.trim(),
          content: formData.value.content.trim()
        }
      });
    }

    if (res.success) {
      uni.showToast({ title: isEditMode.value ? '编辑成功' : '新增成功' });
      hideModal();
      getNoticeList();
    } else {
      uni.showToast({ title: res.message || (isEditMode.value ? '编辑失败' : '新增失败'), icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
  } finally {
    isSubmitting.value = false;
  }
};

// 预览公告
const previewNotice = (item) => {
  previewNoticeInfo.value = { ...item };
  previewVisible.value = true;
};

// 隐藏预览弹窗
const hidePreviewModal = () => {
  previewVisible.value = false;
};

// 删除公告
const deleteNotice = async (noticeId, index) => {
  uni.showModal({
    title: '警告',
    content: '确定要删除该公告吗？删除后不可恢复！',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/notice/delete',
            method: 'DELETE',
            data: { noticeId }
          });
          if (res.success) {
            uni.showToast({ title: '删除成功' });
            noticeList.value.splice(index, 1);
          } else {
            uni.showToast({ title: '删除失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，删除失败', icon: 'none' });
        }
      }
    }
  });
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};
</script>
